//! pefile-compatible ordinal->name resolution for the "special" import libraries
//! (ws2_32.dll, wsock32.dll, oleaut32.dll). imphash resolves ordinals imported from
//! these to the real function name, exactly as pefile / VirusTotal do; every other
//! ordinal import renders "ord<N>". Generated verbatim from pefile 2024.8.26's
//! ordlookup tables; names are pre-lowercased to match imphash lowercasing.
//!
//! DO NOT EDIT BY HAND - regenerate from pefile if the reference tables change.

/// Resolve an ordinal import to its lowercased function name for one of the three
/// special libraries. `dll_lower` is the DLL name WITH extension, lowercased
/// (e.g. "ws2_32.dll"). Returns `None` for non-special libraries or ordinals absent
/// from pefile's table; the caller then renders "ord<N>".
pub fn special_ordinal_name(dll_lower: &str, ordinal: u16) -> Option<&'static str> {
    match dll_lower {
        "ws2_32.dll" => ws2_32(ordinal),
        "wsock32.dll" => wsock32(ordinal),
        "oleaut32.dll" => oleaut32(ordinal),
        _ => None,
    }
}

