#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolves_special_library_ordinals_like_pefile() {
        // Known pefile ordlookup values, lowercased for the imphash.
        assert_eq!(special_ordinal_name("ws2_32.dll", 1), Some("accept"));
        assert_eq!(special_ordinal_name("ws2_32.dll", 115), Some("wsastartup"));
        assert_eq!(
            special_ordinal_name("oleaut32.dll", 2),
            Some("sysallocstring")
        );
    }

    #[test]
    fn lookup_key_is_case_insensitive_only_via_lowercased_input() {
        // Caller passes an already-lowercased name; a non-lowercased key must miss.
        assert_eq!(special_ordinal_name("WS2_32.DLL", 1), None);
    }

    #[test]
    fn non_special_libraries_and_unlisted_ordinals_return_none() {
        assert_eq!(special_ordinal_name("kernel32.dll", 5), None); // not a special lib
        assert_eq!(special_ordinal_name("ws2_32.dll", 60000), None); // ordinal not in table
    }
}
